import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge, Tabs } from '../design-system/Badge/Badge';
import { Input } from '../design-system/Input/Input';
import '../theme/variables.css';

const AI = 'http://localhost:8000';

function FHIRViewer() {
  const [patientId, setPatientId] = useState('1');
  const [fhirData, setFhirData] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('patient');

  const handleQuery = async () => {
    setError(null); setLoading(true);
    try {
      const [p, c, o, m] = await Promise.all([
        fetch(`${AI}/api/v1/fhir/Patient/${patientId}`).then(r=>r.ok?r.json():null),
        fetch(`${AI}/api/v1/fhir/Condition?patient=${patientId}`).then(r=>r.ok?r.json():null),
        fetch(`${AI}/api/v1/fhir/Observation?patient=${patientId}`).then(r=>r.ok?r.json():null),
        fetch(`${AI}/api/v1/fhir/MedicationRequest?patient=${patientId}`).then(r=>r.ok?r.json():null),
      ]);
      setFhirData({ patient:p, conditions:c, observations:o, medications:m });
    } catch(e:any) { setError(e.message); }
    finally { setLoading(false); }
  };

  const entries = (d: any) => d?.entry?.length || 0;

  return (
    <div style={{maxWidth:900,margin:'0 auto',padding:'var(--spacing-4)'}}>
      <h1 style={{fontSize:'var(--font-size-2xl)',marginBottom:'var(--spacing-4)'}}>FHIR Interoperability</h1>

      <Card title="Patient Query">
        <div style={{display:'flex',gap:'var(--spacing-3)',alignItems:'end'}}>
          <Input label="Patient ID" value={patientId} onChange={e=>setPatientId(e.target.value)} />
          <Button onClick={handleQuery} disabled={!patientId||loading}>{loading?'Querying...':'Fetch FHIR Resources'}</Button>
        </div>
        {error && <div style={{marginTop:8,padding:8,background:'var(--color-error-light)',borderRadius:4,color:'var(--color-error)'}}>{error}</div>}
      </Card>

      {fhirData && (
        <div style={{marginTop:'var(--spacing-4)'}}>
          <Tabs tabs={[
            {key:'patient',label:'Patient'},
            {key:'conditions',label:`Conditions (${entries(fhirData.conditions)})`},
            {key:'observations',label:`Observations (${entries(fhirData.observations)})`},
            {key:'medications',label:`Medications (${entries(fhirData.medications)})`},
          ]} activeKey={activeTab} onChange={setActiveTab} />

          <div style={{marginTop:'var(--spacing-4)'}}>
            {activeTab==='patient' && fhirData.patient && (
              <Card title={`Patient: ${fhirData.patient.name?.[0]?.given?.[0]||''} ${fhirData.patient.name?.[0]?.family||''}`}>
                <pre style={{fontSize:12,background:'var(--color-neutral-50)',padding:12,borderRadius:8,overflow:'auto',maxHeight:500}}>
                  {JSON.stringify(fhirData.patient, null, 2)}
                </pre>
              </Card>
            )}
            {activeTab==='conditions' && (
              <div>{fhirData.conditions?.entry?.map((e:any,i:number) => {
                const c = e.resource;
                return (
                  <div key={i} style={{padding:8,marginBottom:4,border:'1px solid var(--color-neutral-200)',borderRadius:6}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <Badge variant={c.clinicalStatus?.coding?.[0]?.code==='active'?'warning':'neutral'}>{c.clinicalStatus?.coding?.[0]?.code||'?'}</Badge>
                      <strong>{c.code?.coding?.[0]?.display||c.code?.text}</strong>
                      <span style={{fontSize:12,color:'var(--color-neutral-400)',fontFamily:'monospace'}}>{c.code?.coding?.[0]?.code}</span>
                    </div>
                    {c.onsetDateTime && <div style={{fontSize:12,color:'var(--color-neutral-400)',marginTop:2}}>Onset: {c.onsetDateTime}</div>}
                  </div>
                );
              })}
              {!fhirData.conditions?.total && <p style={{color:'var(--color-neutral-400)'}}>No conditions found.</p>}
              </div>
            )}
            {activeTab==='observations' && (
              <div>{fhirData.observations?.entry?.map((e:any,i:number) => {
                const o = e.resource;
                return (
                  <div key={i} style={{display:'flex',justifyContent:'space-between',padding:8,borderBottom:'1px solid var(--color-neutral-100)'}}>
                    <span>{o.code?.text}</span>
                    <span style={{fontWeight:600}}>{o.valueQuantity?.value} {o.valueQuantity?.unit}</span>
                  </div>
                );
              })}
              {!fhirData.observations?.total && <p style={{color:'var(--color-neutral-400)'}}>No observations found.</p>}
              </div>
            )}
            {activeTab==='medications' && (
              <div>{fhirData.medications?.entry?.map((e:any,i:number) => {
                const m = e.resource;
                return (
                  <div key={i} style={{padding:8,marginBottom:4,border:'1px solid var(--color-neutral-200)',borderRadius:6}}>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <Badge variant={m.status==='active'?'success':'neutral'}>{m.status}</Badge>
                      <strong>{m.medicationCodeableConcept?.text}</strong>
                    </div>
                    {m.dosageInstruction?.[0]?.text && <div style={{fontSize:13,color:'var(--color-neutral-500)',marginTop:2}}>{m.dosageInstruction[0].text}</div>}
                  </div>
                );
              })}
              {!fhirData.medications?.total && <p style={{color:'var(--color-neutral-400)'}}>No medications found.</p>}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

const el = document.getElementById('fhir-root');
if (el) createRoot(el).render(<FHIRViewer />);
